import React, { useEffect, useState } from "react";
import { Table, Button, Tooltip, Select } from "antd";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import { getAdminRfqs } from "../../features/b2b/b2bSlice";
import { Search, FileText, Eye } from "lucide-react";

const RfqList = () => {
  const dispatch = useDispatch();
  const [searchText, setSearchText] = useState("");
  const [filterStatus, setFilterStatus] = useState("all");

  useEffect(() => {
    const params = {};
    if (filterStatus !== "all") params.status = filterStatus;
    if (searchText) params.search = searchText;

    dispatch(getAdminRfqs(params));
  }, [dispatch, searchText, filterStatus]);

  const { rfqs, isLoading } = useSelector((state) => state.b2b);

  const columns = [
    {
      title: "RFQ ID",
      dataIndex: "id",
      render: (id) => (
        <Link
          to={`/admin/b2b/rfq/${id}`}
          className="font-mono text-[11px] font-black text-blue-600 bg-blue-50 px-2.5 py-1 rounded-lg border border-blue-100 uppercase"
        >
          #{id.slice(-6)}
        </Link>
      ),
    },
    {
      title: "Client / Institution",
      dataIndex: "customer",
      render: (customer) => (
        <div className="flex flex-col">
          <span className="font-bold text-slate-800 text-[15px] leading-tight">
            {customer?.institutionName || "Individual Buyer"}
          </span>
          <span className="text-[12px] text-slate-400 font-medium mt-0.5">
            {customer ? `${customer.firstname} ${customer.lastname}` : "Unknown Contact"}
          </span>
        </div>
      ),
    },
    {
      title: "Items Requested",
      dataIndex: "items",
      render: (items) => (
        <span className="font-bold text-slate-700 text-sm">
          {items?.length || 0} Line Items
        </span>
      ),
    },
    {
      title: "RFQ Status",
      dataIndex: "status",
      render: (status) => (
        <div
          className={`status-badge ${
            status === "ACCEPTED"
              ? "success"
              : status === "REJECTED" || status === "EXPIRED"
              ? "danger"
              : status === "QUOTED"
              ? "active"
              : "info"
          }`}
        >
          <div
            className={`w-1.5 h-1.5 rounded-full ${
              status === "ACCEPTED"
                ? "bg-emerald-500"
                : status === "REJECTED" || status === "EXPIRED"
                ? "bg-rose-500"
                : status === "QUOTED"
                ? "bg-blue-500"
                : "bg-amber-400"
            }`}
          />
          {status}
        </div>
      ),
    },
    {
      title: "Submitted At",
      dataIndex: "createdAt",
      render: (date) => (
        <span className="text-slate-500 font-bold text-xs">
          {new Date(date).toLocaleDateString()}
        </span>
      ),
    },
    {
      title: "Actions",
      dataIndex: "id",
      render: (id) => (
        <div className="flex items-center gap-2">
          <Tooltip title="View RFQ / Respond with Quote">
            <Link to={`/admin/b2b/rfq/${id}`}>
              <Button
                type="text"
                icon={<Eye size={18} />}
                className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl w-10 h-10 flex items-center justify-center border border-transparent hover:border-slate-100"
              />
            </Link>
          </Tooltip>
        </div>
      ),
    },
  ];

  const dataSource = rfqs || [];

  return (
    <div className="space-y-8 pb-12">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-[28px] font-bold text-slate-900 tracking-tight">
            Requests for Quotation (RFQ)
          </h1>
          <p className="text-[15px] text-slate-500 mt-1 font-medium">
            Review custom pricing and supply quotes requested by institutional buyers.
          </p>
        </div>
        <div className="relative w-full sm:w-80">
          <Search
            className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"
            size={18}
          />
          <input
            type="text"
            placeholder="Search RFQ or institution..."
            className="pl-10 pr-4 h-11 w-full bg-white border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500/20 text-[14px] font-medium"
            onChange={(e) => setSearchText(e.target.value)}
          />
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center p-6 border-b border-slate-50 gap-4">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-blue-50 rounded-xl text-blue-600">
              <FileText size={20} />
            </div>
            <div>
              <span className="text-[15px] font-bold text-black border-slate-100 pr-4 mr-4 border-r">
                RFQ Dashboard
              </span>
              <span className="text-[14px] text-slate-500 font-medium">
                Quotes: <span className="text-black font-bold">{dataSource.length}</span>
              </span>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-[13px] font-bold text-slate-400 uppercase tracking-widest">
              Status:
            </span>
            <Select
              defaultValue="all"
              onChange={(val) => setFilterStatus(val)}
              className="w-44 modern-select"
              bordered={false}
            >
              <Select.Option value="all">All Statuses</Select.Option>
              <Select.Option value="SUBMITTED">Submitted</Select.Option>
              <Select.Option value="UNDER_REVIEW">Under Review</Select.Option>
              <Select.Option value="QUOTED">Quoted / Responded</Select.Option>
              <Select.Option value="ACCEPTED">Accepted</Select.Option>
              <Select.Option value="REJECTED">Rejected</Select.Option>
              <Select.Option value="EXPIRED">Expired</Select.Option>
            </Select>
          </div>
        </div>

        <Table
          columns={columns}
          dataSource={dataSource}
          loading={isLoading}
          pagination={{
            pageSize: 10,
            className: "px-6 py-4",
          }}
          className="modern-table"
          rowKey="id"
        />
      </div>
    </div>
  );
};

export default RfqList;
